<template><el-card><template #header>工具测试</template><div class="two-col"><el-card><el-select v-model="toolId" style="width:100%"><el-option v-for="t in tools" :key="t.id" :label="t.name" :value="t.id"/></el-select><JsonEditor v-model="payload" class="mt"/><el-button type="primary" class="mt" :loading="loading" @click="call">调用工具</el-button></el-card><el-card><template #header>模拟响应</template><EmptyState v-if="!result"/><el-descriptions v-else :column="1" border><el-descriptions-item label="错误码">{{result.code}}</el-descriptions-item><el-descriptions-item label="耗时">{{result.elapsed}}</el-descriptions-item><el-descriptions-item label="响应"><pre>{{result.data}}</pre></el-descriptions-item><el-descriptions-item label="日志"><p v-for="l in result.logs" :key="l">{{l}}</p></el-descriptions-item></el-descriptions></el-card></div></el-card></template>
<script setup lang="ts">import { ref } from 'vue'; import { tools } from '@/mock/data'; import { api } from '@/api'; import JsonEditor from '@/components/JsonEditor.vue'; import EmptyState from '@/components/EmptyState.vue'; const toolId=ref(tools[0].id); const payload=ref('{"question":"自然人申请光伏并网需要什么材料？"}'); const result=ref<any>(); const loading=ref(false); async function call(){loading.value=true; result.value=await api.simulateTool({toolId:toolId.value, params:JSON.parse(payload.value)}); loading.value=false}</script>
